function AdminBookings() {
  const navigate = useNavigate();
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter] = useState("");
  const [search, setSearch] = useState("");
  const [updating, setUpdating] = useState(null);

  const load = async () => {
    setLoading(true);
    try {
      const params = filter ? { status: filter } : {};
      if (search) params.search = search;
      const { data } = await bookingsAPI.adminGetAll(params);
      setBookings(data.bookings || []);
    } catch {}
    setLoading(false);
  };

  useEffect(() => {
    load();
  }, [filter]);

  const handleStatusUpdate = async (bookingId, status) => {
    setUpdating(bookingId);
    try {
      await bookingsAPI.adminUpdateStatus(bookingId, { status });
      toast.success(`Status updated to ${status}`);
      load();
    } catch {
      toast.error("Failed to update status");
    }
    setUpdating(null);
  };

  const STATUS_OPTIONS = [
    "Pending",
    "Confirmed",
    "In Progress",
    "Completed",
    "Cancelled",
  ];
  const statusColor = {
    Pending: "#FEF9C3",
    Confirmed: "#DBEAFE",
    "In Progress": "#E0F2FE",
    Completed: "#DCFCE7",
    Cancelled: "#FEE2E2",
  };
  const statusText = {
    Pending: "#713F12",
    Confirmed: "#1E3A8A",
    "In Progress": "#0C4A6E",
    Completed: "#166534",
    Cancelled: "#7F1D1D",
  };

  return (
    <div>
      <div
        style={{
          display: "flex",
          gap: 12,
          marginBottom: 20,
          flexWrap: "wrap",
          alignItems: "center",
        }}
      >
        <input
          placeholder="Search bookings..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && load()}
          style={{
            padding: "8px 14px",
            border: "1px solid var(--border)",
            borderRadius: "var(--radius-md)",
            fontSize: 14,
            fontFamily: "var(--font-body)",
            outline: "none",
            width: 220,
          }}
        />
        {["", ...STATUS_OPTIONS].map((s) => (
          <button
            key={s}
            onClick={() => setFilter(s)}
            style={{
              padding: "8px 14px",
              borderRadius: "var(--radius-full)",
              border: "1px solid var(--border)",
              background: filter === s ? "var(--primary)" : "white",
              color: filter === s ? "white" : "var(--text-secondary)",
              cursor: "pointer",
              fontSize: 13,
              fontWeight: 600,
              transition: "all 0.2s",
              fontFamily: "var(--font-display)",
            }}
          >
            {s || "All"}
          </button>
        ))}
      </div>
      {loading ? (
        <div
          className="spinner"
          style={{ margin: "40px auto", display: "block" }}
        />
      ) : (
        <div className="table-wrapper">
          <table>
            <thead>
              <tr>
                <th>ID</th>
                <th>Customer</th>
                <th>Service</th>
                <th>Date/Time</th>
                <th>Status</th>
                <th>Amount</th>
                <th>Update Status</th>
              </tr>
            </thead>
            <tbody>
              {bookings.map((b) => (
                <tr key={b._id}>
                  <td
                    style={{
                      fontWeight: 600,
                      color: "var(--primary)",
                      fontSize: 13,
                    }}
                  >
                    {b.bookingId}
                  </td>
                  <td>
                    <div style={{ fontWeight: 600, fontSize: 14 }}>
                      {b.user?.name}
                    </div>
                    <div style={{ fontSize: 12, color: "var(--text-muted)" }}>
                      {b.user?.mobile}
                    </div>
                  </td>
                  <td
                    style={{
                      maxWidth: 140,
                      overflow: "hidden",
                      textOverflow: "ellipsis",
                      whiteSpace: "nowrap",
                      fontSize: 13,
                    }}
                  >
                    {b.serviceSnapshot?.name}
                  </td>
                  <td style={{ fontSize: 12, whiteSpace: "nowrap" }}>
                    {new Date(b.scheduledDate).toLocaleDateString("en-IN")}
                    <br />
                    {b.scheduledTime}
                  </td>
                  <td>
                    <span
                      className="badge"
                      style={{
                        background: statusColor[b.status],
                        color: statusText[b.status],
                      }}
                    >
                      {b.status}
                    </span>
                  </td>
                  <td style={{ fontWeight: 700 }}>₹{b.payment?.amount}</td>
                  <td>
                    <select
                      value={b.status}
                      disabled={updating === b._id}
                      onChange={(e) =>
                        handleStatusUpdate(b._id, e.target.value)
                      }
                      style={{
                        padding: "6px 10px",
                        border: "1px solid var(--border)",
                        borderRadius: "var(--radius-sm)",
                        fontSize: 13,
                        cursor: "pointer",
                        fontFamily: "var(--font-body)",
                        background: "white",
                      }}
                    >
                      {STATUS_OPTIONS.map((s) => (
                        <option key={s} value={s}>
                          {s}
                        </option>
                      ))}
                    </select>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
          {bookings.length === 0 && (
            <div
              style={{
                textAlign: "center",
                padding: "40px",
                color: "var(--text-muted)",
              }}
            >
              No bookings found
            </div>
          )}
        </div>
      )}
    </div>
  );
}

